package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.COMMENT;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.SP;
import java.io.Closeable;
import java.io.Flushable;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

class CSVPrinterTest {

    private CSVPrinter printer;
    private Appendable out;
    private CSVFormat format;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecords_withMultipleRowsAndColumns() throws SQLException, IOException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(3);

        // Simulate two rows
        when(resultSet.next()).thenReturn(true, true, false);

        when(resultSet.getString(1)).thenReturn("val11", "val21");
        when(resultSet.getString(2)).thenReturn("val12", "val22");
        when(resultSet.getString(3)).thenReturn("val13", "val23");

        // Spy on printer to verify print and println calls
        CSVPrinter spyPrinter = spy(printer);

        // Use doCallRealMethod() to ensure printRecords calls real method on spy
        doCallRealMethod().when(spyPrinter).printRecords(any(ResultSet.class));

        spyPrinter.printRecords(resultSet);

        InOrder inOrder = inOrder(spyPrinter);

        // For first row
        inOrder.verify(spyPrinter).print("val11");
        inOrder.verify(spyPrinter).print("val12");
        inOrder.verify(spyPrinter).print("val13");
        inOrder.verify(spyPrinter).println();

        // For second row
        inOrder.verify(spyPrinter).print("val21");
        inOrder.verify(spyPrinter).print("val22");
        inOrder.verify(spyPrinter).print("val23");
        inOrder.verify(spyPrinter).println();

        // Verify no more interactions
        verifyNoMoreInteractions(spyPrinter);
    }

    @Test
    void testPrintRecords_withZeroColumns() throws SQLException, IOException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(0);

        when(resultSet.next()).thenReturn(true, false);

        CSVPrinter spyPrinter = spy(printer);

        doCallRealMethod().when(spyPrinter).printRecords(any(ResultSet.class));

        spyPrinter.printRecords(resultSet);

        // Since columnCount=0, print() should not be called, only println() once
        verify(spyPrinter, times(0)).print(any());
        verify(spyPrinter, times(1)).println();
    }

    @Test
    void testPrintRecords_withSQLException() throws SQLException {
        ResultSet resultSet = mock(ResultSet.class);
        when(resultSet.getMetaData()).thenThrow(new SQLException("MetaData error"));

        try {
            printer.printRecords(resultSet);
            assert false; // should not reach here
        } catch (SQLException e) {
            // expected
            assert e.getMessage().contains("MetaData error");
        } catch (IOException e) {
            // not expected
            assert false;
        }
    }

    @Test
    void testPrintRecords_withIOException() throws SQLException, IOException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);

        when(resultSet.getMetaData()).thenReturn(metaData);
        when(metaData.getColumnCount()).thenReturn(1);

        when(resultSet.next()).thenReturn(true, false);
        when(resultSet.getString(1)).thenReturn("value");

        CSVPrinter spyPrinter = spy(printer);

        doCallRealMethod().when(spyPrinter).printRecords(any(ResultSet.class));
        doThrow(new IOException("IO error")).when(spyPrinter).print("value");

        try {
            spyPrinter.printRecords(resultSet);
            assert false; // should not reach here
        } catch (IOException e) {
            assert e.getMessage().contains("IO error");
        }
    }
}
